const fs=require("fs");const path=require("path");let _skillRulesCache=null;let _skillRulesCacheTs=0;const SKILL_CACHE_TTL=3e4;function getSkillRules(projectRoot){const now=Date.now();if(_skillRulesCache&&now-_skillRulesCacheTs<SKILL_CACHE_TTL){return _skillRulesCache}try{const rulesPath=path.join(projectRoot,"skill-rules.json");if(!fs.existsSync(rulesPath))return null;_skillRulesCache=JSON.parse(fs.readFileSync(rulesPath,"utf8"));_skillRulesCacheTs=now;return _skillRulesCache}catch(_){return null}}function classifyPromptComplexity(prompt){const trimmed=prompt.trim();const wordCount=trimmed.split(/\s+/).length;if(wordCount<=10){if(/^\/\w+/.test(trimmed))return"TRIVIAL";if(/^(yes|no|y|n|네|아니|ㅇ|ㄴ|ok|확인|맞아|응|ㅇㅇ)$/i.test(trimmed))return"TRIVIAL";if(wordCount<=3&&!/KiiPS|빌드|배포|deploy|build|기능|feature|아키텍처|architecture|설계|리팩토링|refactor|테스트|test|분석|analyze/i.test(trimmed))return"TRIVIAL";if(/^(안녕|hello|hi|thanks|감사|고마워|ㄱㅅ)/i.test(trimmed))return"TRIVIAL"}const complexIndicators=[/전체.*빌드|all.*build|모든.*서비스/i,/배포.*실행|deploy.*and.*run/i,/아키텍처|architecture|설계.*검토/i,/병렬|parallel|팀.*에이전트|team.*agent/i,/KiiPS-[A-Z]+.*KiiPS-[A-Z]+/,/(전체|모든|all|multi|multiple|여러).*(모듈|서비스|module|service)/i,/리팩토링.*전체|refactor.*all/i];if(complexIndicators.some(p=>p.test(prompt)))return"COMPLEX";return"STANDARD"}async function onUserPromptSubmit(prompt,context){try{const complexity=classifyPromptComplexity(prompt);if(complexity==="TRIVIAL"){return prompt}const projectRoot=context.workspaceRoot||process.cwd();const messages=[];const skillActivation=activateSkills(prompt,projectRoot);if(skillActivation)messages.push(skillActivation);const rules=getSkillRules(projectRoot);if(rules){const violations=checkBlockRules(prompt,rules);if(violations.length>0){const blockMsg=violations.map(v=>`[BLOCKED] ${v.skill}:${v.ruleId}\n  ${v.severity==="critical"?"🔴":"⚠️"} ${v.message}`).join("\n");messages.push(blockMsg)}}const moduleContext=detectKiipsModules(prompt);if(moduleContext)messages.push(moduleContext);const specialistRoute=routeToSpecialist(prompt);if(specialistRoute)messages.push(specialistRoute);const geminiReview=loadLatestGeminiReview();if(geminiReview)messages.unshift(geminiReview);if(complexity==="COMPLEX"){const agentCapabilities=checkAgentCapabilities(prompt);if(agentCapabilities)messages.push(agentCapabilities);const taskDecomposition=suggestTaskDecomposition(prompt);if(taskDecomposition)messages.push(taskDecomposition);const managerRouting=detectManagerAgent(prompt);if(managerRouting)messages.push(managerRouting);const effortScaling=assessEffortScaling(prompt);if(effortScaling)messages.push(effortScaling)}if(messages.length>0){return messages.join("\n\n")+"\n\n"+prompt}return prompt}catch(error){console.error("[UserPromptSubmit] Error:",error.message);return prompt}}const SPECIALIST_ROUTES=[{agent:"security-reviewer",keywords:["보안","xss","csrf","injection","취약점","security","vulnerability","인증","인가","auth"],priority:1},{agent:"kiips-realgrid-generator",keywords:["realgrid","그리드 생성","gridview","dataprovider","그리드 코드"],priority:2},{agent:"kiips-architect",keywords:["아키텍처","architecture","설계 검토","모듈 구조","시스템 설계"],priority:2},{agent:"verify-agent",keywords:["검증","verify","빌드 확인","테스트 확인","증거 기반"],priority:1},{agent:"code-simplifier",keywords:["단순화","simplify","리팩토링","refactor","복잡도","complexity"],priority:3},{agent:"checklist-generator",keywords:["체크리스트","checklist","리뷰 목록","검증 목록"],priority:3},{agent:"kiips-developer",keywords:["구현","코딩","디버깅","버그 수정","bug fix","implement","coding"],priority:4},{agent:"kiips-ui-designer",keywords:["ui 설계","화면 설계","jsp 디자인","레이아웃 설계","디자인 시안"],priority:4}];function routeToSpecialist(prompt){try{const lowerPrompt=prompt.toLowerCase();const matched=SPECIALIST_ROUTES.filter(r=>r.keywords.some(kw=>lowerPrompt.includes(kw))).sort((a,b)=>a.priority-b.priority);if(matched.length===0)return null;const primary=matched[0];const others=matched.slice(1,3).map(m=>m.agent);let msg=`[Specialist] ${primary.agent}`;if(others.length>0){msg+=` (also: ${others.join(", ")})`}return msg}catch(_){return null}}function checkAgentCapabilities(prompt){try{const lowerPrompt=prompt.toLowerCase();const taskMap={build:["빌드","build","maven"],deploy:["배포","deploy","start"],api_test:["테스트","test","api"],architecture_review:["아키텍처","설계","architecture"],log_analysis:["로그","log","디버그"]};const detected=Object.entries(taskMap).filter(([,kws])=>kws.some(kw=>lowerPrompt.includes(kw))).map(([type])=>type);if(detected.length===0)return null;return`[L3 Match] ${detected.join(", ")}`}catch(_){return null}}function suggestTaskDecomposition(prompt){const complexPatterns=[{pattern:/전체.*빌드|all.*build|모든.*서비스/i,type:"multi_service_build"},{pattern:/배포.*실행|deploy.*and.*run/i,type:"build_and_deploy"},{pattern:/새.*기능|new.*feature|feature.*개발/i,type:"feature_development"},{pattern:/리팩토링|refactor|코드.*개선/i,type:"code_refactoring"}];const match=complexPatterns.find(({pattern})=>pattern.test(prompt));if(!match)return null;return`[L4 Task] Complex: ${match.type}`}function detectManagerAgent(prompt){try{const lowerPrompt=prompt.toLowerCase();const rules=[{manager:"build-manager",keywords:["빌드","build","maven","compile","package","mvn"]},{manager:"deployment-manager",keywords:["배포","deploy","start","stop","restart","시작","중지","재시작"]},{manager:"feature-manager",keywords:["기능","feature","개발","구현","implement"]},{manager:"ui-manager",keywords:["UI","화면","페이지","그리드","차트","JSP","RealGrid","ApexCharts","반응형","접근성"]}];const matched=rules.find(r=>r.keywords.some(kw=>lowerPrompt.includes(kw.toLowerCase())));if(!matched)return null;let complexity="simple";if(/(전체|모든|all|multi|multiple|여러)/.test(lowerPrompt))complexity="multi_service";else if(/(배포.*테스트|build.*deploy|빌드.*배포)/.test(lowerPrompt))complexity="complex";return`[L4.5 Manager] ${matched.manager} (${complexity})`}catch(_){return null}}function detectKiipsModules(prompt){const modulePattern=/KiiPS-([A-Z]{2,10})/gi;const matches=prompt.match(modulePattern)||[];const uniqueModules=[...new Set(matches.map(m=>m.toUpperCase()))];if(uniqueModules.length===0)return null;const protectedModules=["KIIPS-HUB","KIIPS-COMMON","KIIPS-UTILS","KIIPS-APIGATEWAY","KIIPS-LOGIN"];const targetProtected=uniqueModules.filter(m=>protectedModules.includes(m));let msg=`[Modules] ${uniqueModules.join(", ")}`;if(targetProtected.length>0){msg+=` | Protected: ${targetProtected.join(", ")}`}return msg}function activateSkills(prompt,projectRoot){const rules=getSkillRules(projectRoot);if(!rules)return null;const activatedSkills=[];for(const[skillName,rule]of Object.entries(rules)){if(shouldActivateSkill(prompt,rule)){activatedSkills.push({name:skillName,priority:rule.priority})}}const priorityOrder={critical:0,high:1,normal:2,low:3};activatedSkills.sort((a,b)=>(priorityOrder[a.priority]||3)-(priorityOrder[b.priority]||3));if(activatedSkills.length===0)return null;const critical=activatedSkills.filter(s=>s.priority==="critical").map(s=>"!"+s.name);const others=activatedSkills.filter(s=>s.priority!=="critical").map(s=>s.name);return`[Skills] ${[...critical,...others].join(", ")}`}function checkBlockRules(prompt,rules){const violations=[];for(const[skillName,rule]of Object.entries(rules)){if(rule.enforcement!=="block"||!rule.blockRules)continue;for(const blockRule of rule.blockRules){try{if(new RegExp(blockRule.pattern,"i").test(prompt)){violations.push({skill:skillName,ruleId:blockRule.id,message:blockRule.message,severity:blockRule.severity})}}catch(_){continue}}}return violations}function shouldActivateSkill(prompt,rule){const lowerPrompt=prompt.toLowerCase();if(rule.promptTriggers?.keywords){if(rule.promptTriggers.keywords.some(kw=>lowerPrompt.includes(kw.toLowerCase())))return true}if(rule.promptTriggers?.intentPatterns){if(rule.promptTriggers.intentPatterns.some(pattern=>{try{return new RegExp(pattern,"i").test(prompt)}catch(_){return false}}))return true}return false}function loadLatestGeminiReview(){try{const reviewsDir=path.join(__dirname,"../gemini-bridge/reviews");if(!fs.existsSync(reviewsDir))return null;const allFiles=fs.readdirSync(reviewsDir).filter(f=>f.endsWith(".json")).sort((a,b)=>b.localeCompare(a));const maxScan=Math.min(allFiles.length,5);for(let i=0;i<maxScan;i++){try{const fullPath=path.join(reviewsDir,allFiles[i]);const data=JSON.parse(fs.readFileSync(fullPath,"utf8"));if(data.status!=="completed")continue;data.status="shown";data.shownAt=(new Date).toISOString();fs.writeFileSync(fullPath,JSON.stringify(data,null,2),"utf8");const attention=data.needsAttention?"ATTENTION":"OK";let msg=`[GEMINI] ${attention} - ${data.summary||data.verdict||"(no summary)"}`;const criticals=(data.issues||[]).filter(i=>i.severity==="critical");if(criticals.length>0){msg+="\n  CRITICAL: "+criticals.map(i=>i.text).join(" | ")}return msg}catch(_){continue}}return null}catch(_){return null}}function assessEffortScaling(prompt){try{const lowerPrompt=prompt.toLowerCase();let score=0;if([/여러|multiple|전체|모든|all|다수/i,/Controller.*Service|Service.*Mapper/i,/KiiPS-[A-Z]+.*KiiPS-[A-Z]+/,/파일.*파일|file.*file/i].some(p=>p.test(prompt)))score+=2;else if(![/이\s*파일|this\s*file|단일|single/i].some(p=>p.test(prompt)))score+=1;const layers=["controller","service","mapper","dao","jsp","scss","javascript","jquery","sql","query","repository"].filter(l=>lowerPrompt.includes(l));score+=layers.length>=3?2:layers.length>=1?1:0;if([/테스트|검증|확인|test|verify|validation|qa|quality/i,/junit|mock|postman|api\s*test/i].some(p=>p.test(prompt)))score+=2;if([/조사|분석|탐색|찾아|파악|explore|investigate|analyze|research/i,/왜|why|원인|cause|root\s*cause/i].some(p=>p.test(prompt)))score+=2;if(score<=2)return null;const level=score<=4?"SIMPLE":score<=6?"MODERATE":"COMPLEX";const agents=score<=4?"1 agent":score<=6?"2-3 agents":"5+ agents";return`[Effort] ${level} (${score}/8) -> ${agents}`}catch(_){return null}}if(require.main===module){const chunks=[];process.stdin.setEncoding("utf8");process.stdin.on("data",chunk=>chunks.push(chunk));process.stdin.on("end",async()=>{try{const input=chunks.join("");if(!input.trim()){process.exit(0)}const event=JSON.parse(input);const prompt=event.prompt||event.user_prompt||"";const context={workspaceRoot:event.cwd||event.workspace_root||process.cwd()};const result=await onUserPromptSubmit(prompt,context);if(result&&result!==prompt){process.stdout.write(result)}process.exit(0)}catch(e){process.stderr.write(`[UserPromptSubmit] Error: ${e.message}\n`);process.exit(0)}});const safetyTimer=setTimeout(()=>{process.stderr.write("[UserPromptSubmit] stdin timeout (10s)\n");process.exit(0)},1e4);process.stdin.on("end",()=>clearTimeout(safetyTimer));process.stdin.resume()}module.exports={onUserPromptSubmit:onUserPromptSubmit,classifyPromptComplexity:classifyPromptComplexity};